import{_ as t,o as r,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Email Link Debugger","description":"","frontmatter":{"title":"Email Link Debugger","slug":"universal-email-link-debugger"},"headers":[],"relativePath":"marketer-hub/universal-email-link-debugger.md","filePath":"marketer-hub/universal-email-link-debugger.md"}'),o={name:"marketer-hub/universal-email-link-debugger.md"};function s(a,e,l,u,h,p){return r(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch includes several internal mechanisms to ensure all of our links are functioning as expected. To help give you better insight into possible issues with your email links, we&#39;ve provided an external-facing debug tool to help you understand what is going on under the hood with your UE links.</p><div class="info custom-block"><p class="custom-block-title">ESP Debugging</p><p>This tool is used to debug issues generating from your ESP; i.e. Branch is receiving an error from the ESP, resulting in a non-functioning email link.</p></div><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><p>Retrieve the email link that is causing issues.</p></li><li><p>In the address bar of your browser:</p><ol><li>Copy and paste the UE link,</li><li>Append <code>$debug=true</code> to the end of the link.</li></ol></li><li><p>Hit <strong>Enter/Return</strong> to load the link in the browser.</p></li><li><p>View the results on the resulting <strong>Branch ESP Debugger</strong> page.</p></li></ol><h2 id="interpret-the-results" tabindex="-1">Interpret the Results <a class="header-anchor" href="#interpret-the-results" aria-label="Permalink to &quot;Interpret the Results&quot;">​</a></h2><p><strong>Original Email Link</strong></p><p>The email link you are debugging by appending <code>$debug=true</code> and viewing in your browser.</p><p><strong>ESP Route/Proxy</strong></p><p>The server for the ESP associated with the link.</p><p><strong>ESP Response Status Code</strong></p><p>The status code sent by the ESP in response to Branch&#39;s ping to their servers. Please refer to the ESP&#39;s documentation for definitions of their status codes to gain further insight into why the link failed.</p><p><strong>Branch Generated Location</strong></p><p>The resulting link Branch generates to route users according to your pre-selected routing options in the Branch Dashboard.</p><p>If the request failed, we will show the fallback URL users were sent to instead.</p><p><strong>ESP Debug cURL Request</strong></p><p>The actual cURL request Branch sends to the ESP in order to serve the link.</p>',17)])])}const c=t(o,[["render",s]]);export{g as __pageData,c as default};
